// Update command history and prepare for reflection
const currentState = $('Command Generator Agent').first().json;
const commandOutput = $('Command Generator Agent').first().json.output || '';
const extractedResult = $input.first().json;

// Get the command that was executed (clean it up)
const command = commandOutput
  .replace('COMMAND:', '')
  .replace(/[\"\'\`]/g, '')
  .trim();

// Get command history from current state
const commandHistory = currentState.commandHistory || [];

// Add new command to history
commandHistory.push({
  command: command,
  output: JSON.stringify(extractedResult.command_output || extractedResult),
  status: extractedResult.execution_status || 'completed'
});

const newIteration = (currentState.iteration || 0) + 1;

return {
  json: {
    chatInput: currentState.chatInput || currentState.originalQuery,
    originalQuery: currentState.originalQuery,
    iteration: newIteration,
    maxIterations: currentState.maxIterations || 5,
    commandHistory: commandHistory,
    lastResult: extractedResult,
    shouldContinue: true,
    finalAnswer: null
  }
};

