// Decision logic: should we continue or finish?
const item = $input.first().json;
const reflectionOutput = item.output || '';

console.log('=== DECISION LOGIC DEBUG ===');
console.log('Iteration:', item.iteration, '/', item.maxIterations);
console.log('Reflection output:', reflectionOutput);

let shouldContinue = true;
let finalAnswer = null;

// Check if we've hit max iterations - MUST stop
if (item.iteration >= item.maxIterations) {
  console.log('Max iterations reached - forcing stop');
  shouldContinue = false;

  // Extract answer from reflection or generate summary
  const answerMatch = reflectionOutput.match(/FINAL_ANSWER:\s*(.+)/s);
  if (answerMatch) {
    finalAnswer = answerMatch[1].trim();
  } else {
    const history = item.commandHistory || [];
    finalAnswer = `Max iterations (${item.maxIterations}) reached.\n\nResults:\n\n` + 
      history.map((cmd, idx) => `${idx + 1}. Command: ${cmd.command}\n   Output: ${cmd.output}\n   Status: ${cmd.status}`).join('\n\n');
  }
}
// Check if reflection says we're done
else if (reflectionOutput.includes('FINAL_ANSWER:')) {
  console.log('Reflection says FINAL_ANSWER - stopping');
  shouldContinue = false;
  const answerMatch = reflectionOutput.match(/FINAL_ANSWER:\s*(.+)/s);
  finalAnswer = answerMatch ? answerMatch[1].trim() : 'Task completed.';
}
// Check if reflection says continue
else if (reflectionOutput.includes('CONTINUE')) {
  console.log('Reflection says CONTINUE - continuing');
  shouldContinue = true;
}
// Default: if unclear, stop after a few iterations
else if (item.iteration >= 3) {
  console.log('Unclear response after 3 iterations - stopping');
  shouldContinue = false;
  const history = item.commandHistory || [];
  finalAnswer = 'Completed available commands:\n\n' + 
    history.map((cmd, idx) => `${idx + 1}. ${cmd.command}\n   Result: ${cmd.output}`).join('\n\n');
}

console.log('Decision: shouldContinue =', shouldContinue);
console.log('Final answer:', finalAnswer);

return {
  json: {
    chatInput: item.chatInput,
    originalQuery: item.originalQuery,
    iteration: item.iteration,
    maxIterations: item.maxIterations,
    commandHistory: item.commandHistory,
    shouldContinue: shouldContinue,
    finalAnswer: finalAnswer,
    reflectionOutput: reflectionOutput
  }
};

// Pass state to next iteration
const state = $input.first().json;

console.log('=== LOOP BACK ===');
console.log('Passing state for iteration:', state.iteration);

return {
  json: {
    chatInput: state.chatInput,
    originalQuery: state.originalQuery,
    iteration: state.iteration,
    maxIterations: state.maxIterations,
    commandHistory: state.commandHistory,
    shouldContinue: state.shouldContinue,
    finalAnswer: null
  }
};

// Initialize workflow state
const chatInput = $input.first().json.chatInput;

return {
  json: {
    chatInput: chatInput,
    originalQuery: chatInput,
    iteration: 0,
    maxIterations: 5,
    commandHistory: [],
    shouldContinue: true,
    finalAnswer: null
  }
};
